/**
 * MobileChatPanel — Sección del bloque Sala · Mobile (Voyager DS)
 * Fuente: Figma VOYAGER · Frame 1000023075 (panel glass del chat mobile)
 *
 * Fondo glass (blanco 8% + blur) pegado debajo del header. Borde gradiente con
 * técnica de máscara (::before recortado) para no rellenar el interior. Al fondo,
 * la ProgressBar en variante "rainbow" (horizontal, no diagonal). Slot `children`
 * para el contenido del chat (mensajes, etc.).
 */

"use client";

import type { JSX, ReactNode } from "react";
import ProgressBar from "../../components/ProgressBar/ProgressBar";

export const MOBILECHATPANEL_WIDTH = 420;

const STYLE_ID = "concorde-smchatpanel-styles";

const SMCHATPANEL_STYLES = `
.smchatpanel {
  position: relative;
  width: ${MOBILECHATPANEL_WIDTH}px;
  border-radius: 0 0 16px 16px;
  background: rgba(255,255,255,0.08);
  backdrop-filter: blur(14px);
  -webkit-backdrop-filter: blur(14px);
  box-shadow: rgba(0,0,0,0.35) 0px 0px 10px 4px;
  overflow: hidden;
}
/* Borde gradiente sin rellenar el interior (glass real) */
.smchatpanel::before {
  content: "";
  position: absolute;
  inset: 0;
  border-radius: inherit;
  padding: 1.5px;
  background: linear-gradient(120deg, #ffffff 0%, #F4AC59 22%, #8460E5 74.5%, #ffffff 100%);
  -webkit-mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
  -webkit-mask-composite: xor;
  mask-composite: exclude;
  pointer-events: none;
}
`;

let _stylesInjected = false;

export interface MobileChatPanelProps {
  /** Alto del panel en px (default 670) */
  height?: number;
  /** Progreso del bid 0-100 (default 40) */
  progress?: number;
  children?: ReactNode;
  className?: string;
}

export default function MobileChatPanel({
  height = 670,
  progress = 40,
  children,
  className = "",
}: MobileChatPanelProps): JSX.Element {
  if (typeof document !== "undefined" && !_stylesInjected) {
    if (!document.getElementById(STYLE_ID)) {
      const el = document.createElement("style");
      el.id = STYLE_ID;
      el.textContent = SMCHATPANEL_STYLES;
      document.head.appendChild(el);
    }
    _stylesInjected = true;
  }

  return (
    <>
      <style id={`${STYLE_ID}-ssr`} suppressHydrationWarning dangerouslySetInnerHTML={{ __html: SMCHATPANEL_STYLES }} />
      <div className={`smchatpanel ${className}`.trim()} style={{ height }}>
        {children}
        {/* ProgressBar rainbow pegada al fondo */}
        <div style={{ position: "absolute", left: 0, right: 0, bottom: 0 }}>
          <ProgressBar variant="rainbow" value={progress} aria-label="Tiempo de bid" />
        </div>
      </div>
    </>
  );
}

/**
 * MobileHeader — Sección del bloque Sala · Mobile (Voyager DS)
 * Fuente: Figma VOYAGER · "Group 4" (header sala mobile · 420×95)
 *
 * NO es componente registrado: es una sección del bloque. Dos bloques cuadrados
 * (sin esquinas redondeadas), pegados:
 *   · Izquierda 310×95 → tarjeta de la sala (gradiente naranja→morado, borde
 *     gradiente). Título + Signal (white) + vendedor + fila de pills.
 *   · Derecha   110×95 → imagen del carro (slot por prop) con borde gradiente y
 *     placa glass.
 * Pills glass 50×22 (reusa StatPill glass). Pill naranja 60×22. Los puntos
 * amarillos del Figma son guías → se ignoran. Copia tal cual del SVG.
 */

"use client";

import type { JSX } from "react";
import Signal from "../../components/Signal/Signal";
import StatPill from "../Sala/StatPill";

export const MOBILEHEADER_WIDTH = 420;
export const MOBILEHEADER_HEIGHT = 95;
const INFO_WIDTH = 310;
const CAR_WIDTH = 110;

// Tarjeta sala (paint0 fill + paint1 borde) — diagonal naranja→morado
const INFO_FILL = "linear-gradient(125deg, #ED8936 0%, #ED8936 40%, #8460E5 100%)";
const INFO_BORDER = "linear-gradient(125deg, #ffffff 0%, #F4AC59 22%, #8460E5 74.5%, #ffffff 100%)";
// Pill naranja 60×22 (paint8 fill + paint9 borde)
const LIVE_FILL = "linear-gradient(180deg, #FF9639 0%, #EF852E 40%, #BE3D00 100%)";
const LIVE_BORDER = "linear-gradient(140deg, #FFBC83 0%, rgba(255,255,255,0.45) 40%, #DA6C1E 75%, #FFBC83 100%)";

// Placa glass 54×22 (paint13 fill + paint15 borde lila) · glass real vía máscara
const PLATE_STYLE_ID = "concorde-mh-plate-styles";
const PLATE_STYLES = `
.mh-plate {
  position: absolute;
  left: 50%;
  bottom: 14px;
  transform: translateX(-50%);
  box-sizing: border-box;
  width: 54px;
  height: 22px;
  border-radius: 11px;
  background: linear-gradient(180deg, rgba(255,255,255,0.24) 0%, rgba(255,255,255,0.12) 45%, rgba(255,255,255,0.06) 100%);
  backdrop-filter: blur(5px);
  -webkit-backdrop-filter: blur(5px);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 12px;
  font-weight: 700;
  letter-spacing: 0.02em;
  color: #ffffff;
}
.mh-plate::before {
  content: "";
  position: absolute;
  inset: 0;
  border-radius: inherit;
  padding: 1px;
  background: linear-gradient(140deg, #CFBAFF 0%, #ffffff 35%, #AE8EFF 65%, #CFBAFF 100%);
  -webkit-mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
  -webkit-mask-composite: xor;
  mask-composite: exclude;
  pointer-events: none;
}
`;
let _plateInjected = false;

export interface MobileHeaderProps {
  /** Título del lote (default "Toyota Etios") */
  title?: string;
  /** Año (default "2021") */
  year?: string;
  /** Etiqueta vendedor (default "Vendedor") */
  sellerLabel?: string;
  /** Nombre del vendedor (default "Autoland") */
  seller?: string;
  /** Imagen del carro — slot por prop (default "/demo/bronco.jpg") */
  carSrc?: string;
  /** Placa (default "ABC123") */
  plate?: string;
  /** Bids del usuario (default "11") */
  myBids?: string;
  /** Bids totales (default "111") */
  totalBids?: string;
  /** Participantes (default "18") */
  people?: string;
  /** Código de la subasta para la pill naranja (default "47292") */
  liveCode?: string;
  className?: string;
}

// Flecha del componente SendBidIcon (ARROW_PATH) renderizada como glyph blanco
function ArrowGlyph(): JSX.Element {
  return (
    <svg width="12" height="12" viewBox="15.5 12.5 17 17" fill="none" aria-hidden="true">
      <path
        d="M25.6154 18.0487V14.8164L31.3775 20.5784L25.6154 26.3404V22.9675C21.5399 22.9675 18.5886 24.2324 16.6211 27.1837C17.3237 22.9675 19.8534 18.892 25.6154 18.0487Z"
        fill="#ffffff"
      />
    </svg>
  );
}

// Ícono de grupo de personas — paths exactos del SVG (clip4)
function PeopleGlyph(): JSX.Element {
  return (
    <svg width="13" height="13" viewBox="163.66 84.8196 12 12" fill="none" aria-hidden="true">
      <path d="M173.982 91.2559H172.982C173.082 91.5559 173.182 91.8559 173.182 92.1559V95.9559C173.182 96.1559 173.182 96.2559 173.082 96.3559H174.782C175.382 96.3559 175.882 95.8559 175.882 95.2559V93.1559C175.882 92.1559 175.082 91.2559 173.982 91.2559Z" fill="#ffffff" />
      <path d="M166.36 92.1559C166.36 91.8559 166.46 91.5559 166.56 91.2559H165.56C164.46 91.2559 163.66 92.1559 163.66 93.1559V95.2559C163.66 95.8559 164.16 96.3559 164.76 96.3559H166.46C166.36 96.2559 166.36 96.1559 166.36 95.9559V92.1559Z" fill="#ffffff" />
      <path d="M170.991 90.2742H168.791C167.691 90.2742 166.891 91.0742 166.891 92.0742V95.8742C166.891 96.0742 166.991 96.2742 167.191 96.2742H172.591C172.791 96.2742 172.891 96.0742 172.891 95.8742V92.0742C172.891 91.0742 172.091 90.2742 170.991 90.2742Z" fill="#ffffff" />
      <path d="M169.837 84.8196C168.637 84.8196 167.537 85.8196 167.537 87.1196C167.537 87.9196 168.037 88.6196 168.737 89.0196C169.037 89.2196 169.437 89.3196 169.837 89.3196C170.237 89.3196 170.637 89.2196 170.937 89.0196C171.637 88.6196 172.137 87.9196 172.137 87.1196C172.137 85.8196 171.037 84.8196 169.837 84.8196Z" fill="#ffffff" />
      <path d="M166.098 87.1106C165.198 87.1106 164.398 87.9106 164.398 88.8106C164.398 89.7106 165.198 90.5106 166.098 90.5106C166.398 90.5106 166.598 90.4106 166.798 90.3106C167.198 90.2106 167.398 89.9106 167.598 89.6106C167.798 89.3106 167.798 89.1106 167.798 88.8106C167.798 87.9106 167.098 87.1106 166.098 87.1106Z" fill="#ffffff" />
      <path d="M173.483 87.1106C172.483 87.1106 171.783 87.9106 171.783 88.8106C171.783 89.1106 171.783 89.3106 171.983 89.6106C172.183 89.9106 172.383 90.2106 172.783 90.3106C172.983 90.4106 173.183 90.5106 173.483 90.5106C174.383 90.5106 175.183 89.7106 175.183 88.8106C175.183 87.9106 174.383 87.1106 173.483 87.1106Z" fill="#ffffff" />
    </svg>
  );
}

export default function MobileHeader({
  title = "Toyota Etios",
  year = "2021",
  sellerLabel = "Vendedor",
  seller = "Autoland",
  carSrc = "/demo/bronco.jpg",
  plate = "ABC123",
  myBids = "11",
  totalBids = "111",
  people = "18",
  liveCode = "47292",
  className = "",
}: MobileHeaderProps): JSX.Element {
  if (typeof document !== "undefined" && !_plateInjected) {
    if (!document.getElementById(PLATE_STYLE_ID)) {
      const el = document.createElement("style");
      el.id = PLATE_STYLE_ID;
      el.textContent = PLATE_STYLES;
      document.head.appendChild(el);
    }
    _plateInjected = true;
  }

  return (
    <>
      <style id={`${PLATE_STYLE_ID}-ssr`} suppressHydrationWarning dangerouslySetInnerHTML={{ __html: PLATE_STYLES }} />
      <div
        className={className}
        data-block-section="mobile-header"
        style={{
          display: "flex",
          width: MOBILEHEADER_WIDTH,
          height: MOBILEHEADER_HEIGHT,
          fontFamily: 'var(--vmc-font-display, "Plus Jakarta Sans", -apple-system, sans-serif)',
        }}
      >
        {/* ── Tarjeta sala 310×95 (cuadrada, sin redondeo) ── */}
        <div
          style={{
            boxSizing: "border-box",
            width: INFO_WIDTH,
            height: MOBILEHEADER_HEIGHT,
            backgroundImage: `${INFO_FILL}, ${INFO_BORDER}`,
            backgroundOrigin: "border-box",
            backgroundClip: "padding-box, border-box",
            border: "1.5px solid transparent",
            display: "flex",
            flexDirection: "column",
            justifyContent: "flex-start",
            padding: "10px 14px 14px",
          }}
        >
          {/* Título + Signal (white) — pegados arriba */}
          <div style={{ display: "flex", alignItems: "flex-start", justifyContent: "space-between", marginBottom: 6 }}>
            <span style={{ fontSize: 19, fontWeight: 800, lineHeight: 1, color: "#ffffff", whiteSpace: "nowrap" }}>
              {title} <span style={{ fontWeight: 500 }}>{year}</span>
            </span>
            <Signal variant="white" width={39} height={29} level={4} title="Conectividad" />
          </div>

          {/* Vendedor — arriba, separado de las pills */}
          <span style={{ fontSize: 12, fontWeight: 600, lineHeight: 1, color: "#ffffff" }}>
            {sellerLabel} <span style={{ color: "rgba(255,255,255,0.6)" }}>{seller}</span>
          </span>

          {/* Fila de pills anclada abajo: 3 glass 50×22 + pill naranja 60×22 */}
          <div style={{ marginTop: "auto", display: "flex", alignItems: "center", gap: 9 }}>
            <StatPill variant="glass" label="" value={myBids} icon={<ArrowGlyph />} />
            <StatPill variant="glass" label="" value={totalBids} icon={<ArrowGlyph />} />
            <StatPill variant="glass" label="" value={people} icon={<PeopleGlyph />} />
            <span
              style={{
                boxSizing: "border-box",
                width: 60,
                height: 22,
                marginLeft: "auto",
                borderRadius: 11,
                backgroundImage: `${LIVE_FILL}, ${LIVE_BORDER}`,
                backgroundOrigin: "border-box",
                backgroundClip: "padding-box, border-box",
                border: "1px solid transparent",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                fontSize: 12.5,
                fontWeight: 700,
                color: "#ffffff",
                fontVariantNumeric: "tabular-nums",
              }}
            >
              {liveCode}
            </span>
          </div>
        </div>

        {/* ── Carro 110×95 (cuadrado, borde gradiente, placa glass) ── */}
        <div
          style={{
            position: "relative",
            width: CAR_WIDTH,
            height: MOBILEHEADER_HEIGHT,
            backgroundImage: INFO_BORDER,
            padding: "1.32px",
            boxSizing: "border-box",
            flexShrink: 0,
          }}
        >
          <img
            src={carSrc}
            alt={title}
            style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" }}
          />
          <span className="mh-plate">{plate}</span>
        </div>
      </div>
    </>
  );
}

/**
 * SalaMobile — Bloque de Concorde (Voyager DS)
 *
 * Sala de subasta · versión mobile. Por ahora es solo el lienzo base: un fondo
 * de 420 × 844 con el gradiente morado de marca (#5F3ED8 → #340091 → #140046,
 * paint0 del SVG). Iremos montando las secciones encima (sección por sección,
 * igual que el bloque Sala desktop).
 */

import type { JSX } from "react";
import MobileHeader, { MOBILEHEADER_HEIGHT } from "./MobileHeader";
import MobileChatPanel from "./MobileChatPanel";

export interface SalaMobileProps {
  className?: string;
}

export const SALAMOBILE_WIDTH = 420;
export const SALAMOBILE_HEIGHT = 844;

// Fondo: paint0 (gradiente diagonal #5F3ED8 → #340091 50% → #140046)
export const SALAMOBILE_BG = "linear-gradient(116deg, #5F3ED8 0%, #340091 50%, #140046 100%)";

export default function SalaMobile({ className = "" }: SalaMobileProps): JSX.Element {
  return (
    <div
      className={className}
      data-block="sala-mobile"
      style={{
        position: "relative",
        width: SALAMOBILE_WIDTH,
        height: SALAMOBILE_HEIGHT,
        background: SALAMOBILE_BG,
        overflow: "hidden",
      }}
    >
      {/* Header 420×95 (texto + pills glass + carro) arriba */}
      <div style={{ position: "absolute", top: 0, left: 0 }}>
        <MobileHeader />
      </div>

      {/* Fondo glass del chat 420×670 pegado debajo del header · ProgressBar rainbow al fondo */}
      <div style={{ position: "absolute", top: MOBILEHEADER_HEIGHT, left: 0 }}>
        <MobileChatPanel height={670} progress={40} />
      </div>
    </div>
  );
}

"use client";

/**
 * ProgressBar — Generado por Concorde
 * Fuente: Figma VOYAGER · "Progressbar - Tiempo de bid" (3182:12947)
 *
 * Barra de progreso (track hundido): top recto, esquinas inferiores redondeadas
 * (radio 13), fondo negro 22% con inner-shadows. El relleno (`value` 0-100) usa
 * la gradiente primary (white → #F4AC59 → #8460E5 → white · VYStrokes1). Copia
 * del SVG. Solo `value` — sin estilos editables.
 */

import type { JSX } from "react";

export type ProgressBarVariant = "default" | "rainbow";

export interface ProgressBarProps {
  /** Progreso 0-100 (default 60) */
  value?: number;
  /** Relleno: "default" (gradiente primary diagonal) o "rainbow" (white→#F2CCFF→#CC00FF→#FF0066 horizontal). Default "default". */
  variant?: ProgressBarVariant;
  "aria-label"?: string;
  className?: string;
}

const STYLE_ID = "concorde-progressbar-styles";

const PROGRESSBAR_STYLES = `
.pprogbar {
  position: relative;
  width: 100%;
  height: 22px;
  border-radius: 0 0 13px 13px;
  overflow: hidden;
  background: rgba(0,0,0,0.22);
  box-shadow: inset 0 1px 0 rgba(255,255,255,0.06), inset 0 2px 4px rgba(0,0,0,0.35);
}
.pprogbar__fill {
  position: absolute;
  left: 0;
  top: 0;
  height: 100%;
  background: linear-gradient(135deg, #FFFFFF 0%, #F4AC59 22%, #8460E5 74.5%, #FFFFFF 100%);
  transition: width 0.3s cubic-bezier(0.3,0,0,1);
}
/* Rainbow horizontal (no diagonal): white → lila → magenta → rosa */
.pprogbar__fill--rainbow {
  background: linear-gradient(90deg, #FFFFFF 0%, #F2CCFF 25%, #CC00FF 60%, #FF0066 100%);
  box-shadow: 0 0 6px rgba(255,255,255,0.8), 0 0 14px rgba(204,0,255,0.9), 0 0 30px rgba(255,0,102,0.5);
}
@media (prefers-reduced-motion: reduce) { .pprogbar__fill { transition: none; } }
`;

let _stylesInjected = false;

export default function ProgressBar({
  value = 60,
  variant = "default",
  "aria-label": ariaLabel,
  className = "",
}: ProgressBarProps): JSX.Element {
  if (typeof document !== "undefined" && !_stylesInjected) {
    if (!document.getElementById(STYLE_ID)) {
      const el = document.createElement("style");
      el.id = STYLE_ID;
      el.textContent = PROGRESSBAR_STYLES;
      document.head.appendChild(el);
    }
    _stylesInjected = true;
  }

  const clamped = Math.max(0, Math.min(100, value));

  return (
    <>
      <style id={`${STYLE_ID}-ssr`} suppressHydrationWarning dangerouslySetInnerHTML={{ __html: PROGRESSBAR_STYLES }} />
      <div
        className={`pprogbar ${className}`.trim()}
        role="progressbar"
        aria-valuenow={clamped}
        aria-valuemin={0}
        aria-valuemax={100}
        aria-label={ariaLabel ?? "Tiempo de bid"}
      >
        <div
          className={`pprogbar__fill ${variant === "rainbow" ? "pprogbar__fill--rainbow" : ""}`.trim()}
          style={{ width: `${clamped}%` }}
        />
      </div>
    </>
  );
}

/**
 * Signal — Generado por Concorde
 * Fuente: Figma VOYAGER · "hdr-signal1" (3143:13306)
 *
 * Indicador de señal: 5 barras crecientes (rx1). Las activas con gradiente
 * naranja (#FF9639 → #EF852E → #BE3D00), las inactivas en blanco 20%.
 * `level` (0-5) controla cuántas están activas (default 4). Copia exacta de los
 * paths del SVG. useId para id único.
 */

import { useId } from "react";
import type { JSX } from "react";

export type SignalVariant = "orange" | "white";

export interface SignalProps {
  /** Barras activas (0-5) — default 4 */
  level?: number;
  /** Ancho en px (alto = width × 16/28 si no se pasa `height`) — default 28 */
  width?: number;
  /** Alto en px (override; si se omite, se calcula desde width) */
  height?: number;
  /** Color de las barras activas: "orange" (gradiente) o "white" (sólido). Default "orange". */
  variant?: SignalVariant;
  /** Texto accesible. Si se omite, es decorativo (aria-hidden). */
  title?: string;
  className?: string;
}

const BARS = [
  "M3 12H1C0.447715 12 0 12.4477 0 13V15C0 15.5523 0.447715 16 1 16H3C3.55228 16 4 15.5523 4 15V13C4 12.4477 3.55228 12 3 12Z",
  "M9 9H7C6.44772 9 6 9.44772 6 10V15C6 15.5523 6.44772 16 7 16H9C9.55228 16 10 15.5523 10 15V10C10 9.44772 9.55228 9 9 9Z",
  "M15 6H13C12.4477 6 12 6.44772 12 7V15C12 15.5523 12.4477 16 13 16H15C15.5523 16 16 15.5523 16 15V7C16 6.44772 15.5523 6 15 6Z",
  "M21 3H19C18.4477 3 18 3.44772 18 4V15C18 15.5523 18.4477 16 19 16H21C21.5523 16 22 15.5523 22 15V4C22 3.44772 21.5523 3 21 3Z",
  "M27 0H25C24.4477 0 24 0.447715 24 1V15C24 15.5523 24.4477 16 25 16H27C27.5523 16 28 15.5523 28 15V1C28 0.447715 27.5523 0 27 0Z",
];

export default function Signal({ level = 4, width = 28, height: heightProp, variant = "orange", title, className = "" }: SignalProps): JSX.Element {
  const uid = useId().replace(/:/g, "-");
  const gid = `signal-grad-${uid}`;
  const height = heightProp ?? (width * 16) / 28;
  const activeFill = variant === "white" ? "#ffffff" : `url(#${gid})`;

  return (
    <svg
      width={width}
      height={height}
      viewBox="0 0 28 16"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      className={className}
      role={title ? "img" : undefined}
      aria-hidden={title ? undefined : true}
    >
      {title ? <title>{title}</title> : null}
      {BARS.map(function renderBar(d, i) {
        const active = i < level;
        return <path key={i} d={d} fill={active ? activeFill : "rgba(255,255,255,0.2)"} />;
      })}
      <defs>
        <linearGradient id={gid} x1="0" y1="0" x2="0" y2="1">
          <stop stopColor="#FF9639" />
          <stop offset="0.4" stopColor="#EF852E" />
          <stop offset="1" stopColor="#BE3D00" />
        </linearGradient>
      </defs>
    </svg>
  );
}
